def trimmed_mean(nums):
    if not nums:
        return None

    nums.sort()
    n = len(nums)
    indexes_to_drop = (0, n - 1) if n < 4 else [i for i in range(n // 2 - 1, n - n // 2) if i != (n - 1)]
    trimmed_nums = list(filter(lambda x: x not in nums[indexes_to_drop], nums))
    return sum(trimmed_nums) / len(trimmed_nums)
